function subscription(userId, currentPlan, newPlan) {
  var diff = 0;
  if (currentPlan === 'free') {
    return {
      newPlan: 'free',
      chargeAmount: 0
    }
  };

  switch (newPlan) {

    case 'pro':

      if (currentPlan !== 'free') {

        diff += 10 - 0;
        return {
          newPlan: 'pro',
          chargeAmount: diff
        }
      };

    break;

    case 'enterprise':

      if (currentPlan === 'pro' || currentPlan === 'free') {

        diff -= 50 + 10;
        return {
          newPlan: 'enterprise',
          chargeAmount: diff
        }
      };

    break;
  };
};

